import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

export interface ViteEnv {
  VITE_API_BASE_URL: string;
  VITE_APP_TITLE: string;
}

const initializeApp = async () => {
  const env = import.meta.env as ViteEnv;

  console.log('Application starting...');
  console.log('API Base URL:', env.VITE_API_BASE_URL);
  console.log('App Title:', env.VITE_APP_TITLE);

  if (import.meta.env.DEV) {
    console.log('Running in development mode');
  }

  if (import.meta.env.PROD) {
    console.log('Running in production mode');
  }
};

const rootElement = document.getElementById('root');

if (!rootElement) {
  throw new Error('Root element not found. Make sure there is a <div id="root"></div> in your HTML.');
}

const root = ReactDOM.createRoot(rootElement);

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

initializeApp().catch(console.error);

import type {
  User,
  Category,
  Product,
  Cart,
  CartItem,
  Order,
  OrderItem,
  AuthResponseData,
  ProductListResponse,
  OrderListResponse,
  ApiClientConfig,
  ApiClient,
  ApiResponse,
  AuthApi,
  ProductsApi,
  CartApi,
  OrdersApi,
  ApiService,
} from '../types';

export interface ProductQueryParams {
  page?: number;
  pageSize?: number;
  categoryId?: string;
  search?: string;
  minPrice?: number;
  maxPrice?: number;
  sortBy?: 'name' | 'price' | 'rating' | 'createdAt';
  sortOrder?: 'asc' | 'desc';
}

export interface OrderQueryParams {
  page?: number;
  pageSize?: number;
  status?: Order['status'];
  startDate?: string;
  endDate?: string;
}

export interface AddToCartBody {
  productId: string;
  quantity: number;
}

export interface UpdateCartItemBody {
  quantity: number;
}

export interface CreateOrderBody {
  shippingAddress: string;
  paymentMethod: string;
  notes?: string;
}

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:3000/api';

class ApiClientImpl implements ApiClient {
  private baseURL: string;
  private timeout: number;
  private headers: Record<string, string>;
  private token: string | null = null;

  constructor(config: ApiClientConfig) {
    this.baseURL = config.baseURL;
    this.timeout = config.timeout || 30000;
    this.headers = {
      'Content-Type': 'application/json',
      ...config.headers,
    };
  }

  private async request<T>(
    method: string,
    url: string,
    options: { params?: Record<string, unknown>; data?: unknown } = {}
  ): Promise<ApiResponse<T>> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), this.timeout);

    try {
      let fullUrl = `${this.baseURL}${url}`;

      if (options.params) {
        const searchParams = new URLSearchParams();
        Object.entries(options.params).forEach(([key, value]) => {
          if (value !== undefined && value !== null) {
            searchParams.append(key, String(value));
          }
        });
        const queryString = searchParams.toString();
        if (queryString) {
          fullUrl += `?${queryString}`;
        }
      }

      const headers: Record<string, string> = { ...this.headers };
      if (this.token) {
        headers['Authorization'] = `Bearer ${this.token}`;
      }

      const response = await fetch(fullUrl, {
        method,
        headers,
        body: options.data ? JSON.stringify(options.data) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `HTTP error! status: ${response.status}`);
      }

      const data = await response.json();

      return {
        data,
        status: response.status,
        message: errorData.message,
      };
    } catch (error) {
      clearTimeout(timeoutId);

      if (error instanceof Error) {
        if (error.name === 'AbortError') {
          throw new Error('Request timeout');
        }
        throw error;
      }

      throw new Error('An unexpected error occurred');
    }
  }

  get<T>(url: string, params?: Record<string, unknown>): Promise<ApiResponse<T>> {
    return this.request<T>('GET', url, { params });
  }

  post<T>(url: string, data?: unknown): Promise<ApiResponse<T>> {
    return this.request<T>('POST', url, { data });
  }

  put<T>(url: string, data?: unknown): Promise<ApiResponse<T>> {
    return this.request<T>('PUT', url, { data });
  }

  delete<T>(url: string): Promise<ApiResponse<T>> {
    return this.request<T>('DELETE', url);
  }

  setToken(token: string | null): void {
    this.token = token;
  }
}

const apiClient = new ApiClientImpl({
  baseURL: API_BASE_URL,
  timeout: 30000,
  headers: {
    'Content-Type': 'application/json',
  },
});

const authApi: AuthApi = {
  register: async (data: { name: string; email: string; password: string }): Promise<AuthResponseData> => {
    const response = await apiClient.post<AuthResponseData>('/auth/register', data);
    return response.data;
  },

  login: async (data: { email: string; password: string }): Promise<AuthResponseData> => {
    const response = await apiClient.post<AuthResponseData>('/auth/login', data);
    return response.data;
  },

  getMe: async (): Promise<User> => {
    const response = await apiClient.get<User>('/auth/me');
    return response.data;
  },
};

const productsApi: ProductsApi = {
  getProducts: async (params: ProductQueryParams): Promise<ProductListResponse> => {
    const response = await apiClient.get<ProductListResponse>('/products', params);
    return response.data;
  },

  getProductById: async (id: string): Promise<Product> => {
    const response = await apiClient.get<Product>(`/products/${id}`);
    return response.data;
  },
};

const cartApi: CartApi = {
  getCart: async (): Promise<Cart> => {
    const response = await apiClient.get<Cart>('/cart');
    return response.data;
  },

  addToCart: async (data: AddToCartBody): Promise<Cart> => {
    const response = await apiClient.post<Cart>('/cart/items', data);
    return response.data;
  },

  updateCartItem: async (itemId: string, data: UpdateCartItemBody): Promise<Cart> => {
    const response = await apiClient.put<Cart>(`/cart/items/${itemId}`, data);
    return response.data;
  },

  removeCartItem: async (itemId: string): Promise<Cart> => {
    const response = await apiClient.delete<Cart>(`/cart/items/${itemId}`);
    return response.data;
  },
};

const ordersApi: OrdersApi = {
  getOrders: async (params: OrderQueryParams): Promise<OrderListResponse> => {
    const response = await apiClient.get<OrderListResponse>('/orders', params);
    return response.data;
  },

  createOrder: async (data: CreateOrderBody): Promise<Order> => {
    const response = await apiClient.post<Order>('/orders', data);
    return response.data;
  },

  getOrderById: async (id: string): Promise<Order> => {
    const response = await apiClient.get<Order>(`/orders/${id}`);
    return response.data;
  },
};

export const apiService: ApiService = {
  auth: authApi,
  products: productsApi,
  cart: cartApi,
  orders: ordersApi,
};

export { apiClient };
export default apiService;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import type { RegisterFormData, RegisterFormErrors, RegisterPageState } from '../types';
import Input from '../components/Input';
import Button from '../components/Button';

const Register: React.FC = () => {
  const navigate = useNavigate();
  const [state, setState] = useState<RegisterPageState>({
    formData: {
      name: '',
      email: '',
      password: '',
      confirmPassword: '',
    },
    errors: {},
    isSubmitting: false,
    submitError: null,
  });

  useEffect(() => {
    // Check if user is already logged in
    const token = localStorage.getItem('authToken');
    if (token) {
      navigate('/');
    }
  }, [navigate]);

  const validateForm = (): boolean => {
    const errors: RegisterFormErrors = {};
    const { name, email, password, confirmPassword } = state.formData;

    if (!name) {
      errors.name = 'Name is required';
    } else if (name.length < 2) {
      errors.name = 'Name must be at least 2 characters';
    }

    if (!email) {
      errors.email = 'Email is required';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      errors.email = 'Please enter a valid email address';
    }

    if (!password) {
      errors.password = 'Password is required';
    } else if (password.length < 8) {
      errors.password = 'Password must be at least 8 characters';
    } else if (!/(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/.test(password)) {
      errors.password = 'Password must contain uppercase, lowercase, and a number';
    }

    if (!confirmPassword) {
      errors.confirmPassword = 'Please confirm your password';
    } else if (password !== confirmPassword) {
      errors.confirmPassword = 'Passwords do not match';
    }

    setState(prev => ({ ...prev, errors }));
    return Object.keys(errors).length === 0;
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setState(prev => ({
      ...prev,
      formData: {
        ...prev.formData,
        [name]: value,
      },
      errors: {
        ...prev.errors,
        [name]: undefined,
      },
    }));
  };

  const handleBlur = (e: React.FocusEvent<HTMLInputElement>) => {
    const { name } = e.target;
    validateForm();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setState(prev => ({ ...prev, isSubmitting: true, submitError: null }));

    try {
      // Simulated API call
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Simulate successful registration
      const mockToken = 'mock-jwt-token-' + Date.now();
      const mockUser = {
        id: '1',
        name: state.formData.name,
        email: state.formData.email,
        createdAt: new Date().toISOString(),
      };

      localStorage.setItem('authToken', mockToken);
      localStorage.setItem('user', JSON.stringify(mockUser));

      navigate('/');
    } catch (error) {
      setState(prev => ({
        ...prev,
        submitError: 'Registration failed. Please try again.',
        isSubmitting: false,
      }));
    }
  };

  const { formData, errors, isSubmitting, submitError } = state;

  return (
    <div className="register-page">
      <div className="register-container">
        <div className="register-image">
          <img 
            src="https://picsum.photos/600/800?random=21" 
            alt="Shopping" 
          />
          <div className="register-image-overlay">
            <h2>Join Our Community</h2>
            <p>Get access to exclusive deals and personalized recommendations</p>
          </div>
        </div>

        <div className="register-card">
          <div className="register-header">
            <h1>Create Account</h1>
            <p>Fill in your details to get started</p>
          </div>

          {submitError && (
            <div className="error-message" role="alert">
              {submitError}
            </div>
          )}

          <form onSubmit={handleSubmit} className="register-form">
            <Input
              label="Full Name"
              name="name"
              type="text"
              placeholder="Enter your full name"
              value={formData.name}
              onChange={handleInputChange}
              onBlur={handleBlur}
              error={errors.name}
              required
              fullWidth
              autoComplete="name"
            />

            <Input
              label="Email Address"
              name="email"
              type="email"
              placeholder="Enter your email"
              value={formData.email}
              onChange={handleInputChange}
              onBlur={handleBlur}
              error={errors.email}
              required
              fullWidth
              autoComplete="email"
            />

            <Input
              label="Password"
              name="password"
              type="password"
              placeholder="Create a strong password"
              value={formData.password}
              onChange={handleInputChange}
              onBlur={handleBlur}
              error={errors.password}
              required
              fullWidth
              autoComplete="new-password"
            />

            <div className="password-requirements">
              <p>Password must contain:</p>
              <ul>
                <li className={formData.password.length >= 8 ? 'met' : ''}>At least 8 characters</li>
                <li className={/(?=.*[a-z])/.test(formData.password) ? 'met' : ''}>Lowercase letter</li>
                <li className={/(?=.*[A-Z])/.test(formData.password) ? 'met' : ''}>Uppercase letter</li>
                <li className={/(?=.*\d)/.test(formData.password) ? 'met' : ''}>Number</li>
              </ul>
            </div>

            <Input
              label="Confirm Password"
              name="confirmPassword"
              type="password"
              placeholder="Confirm your password"
              value={formData.confirmPassword}
              onChange={handleInputChange}
              onBlur={handleBlur}
              error={errors.confirmPassword}
              required
              fullWidth
              autoComplete="new-password"
            />

            <div className="terms-conditions">
              <label>
                <input type="checkbox" required />
                <span>
                  I agree to the{' '}
                  <Link to="/terms">Terms of Service</Link> and{' '}
                  <Link to="/privacy">Privacy Policy</Link>
                </span>
              </label>
            </div>

            <Button
              type="submit"
              variant="primary"
              size="lg"
              fullWidth
              loading={isSubmitting}
              disabled={isSubmitting}
            >
              {isSubmitting ? 'Creating account...' : 'Create Account'}
            </Button>
          </form>

          <div className="register-footer">
            <p>
              Already have an account?{' '}
              <Link to="/login" className="login-link">
                Sign in
              </Link>
            </p>
          </div>

          <div className="social-register">
            <div className="divider">
              <span>or register with</span>
            </div>
            <div className="social-buttons">
              <button type="button" className="social-btn social-btn-google" aria-label="Register with Google">
                <span className="social-icon">G</span>
                Google
              </button>
              <button type="button" className="social-btn social-btn-facebook" aria-label="Register with Facebook">
                <span className="social-icon">f</span>
                Facebook
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Register;

import React from 'react';
import type { ProductCardProps, ProductCardBadge } from '../types';
import Button from './Button';

const ProductCard: React.FC<ProductCardProps> = ({
  product,
  onAddToCart,
  onViewDetail,
  isAddingToCart = false,
}) => {
  const getBadge = (): ProductCardBadge | null => {
    // Mock logic for demo purposes
    if (product.price < 100) {
      return { type: 'sale', label: 'Sale' };
    }
    if (product.rating >= 4.5) {
      return { type: 'popular', label: 'Popular' };
    }
    const daysSinceCreated = Math.floor(
      (Date.now() - new Date(product.createdAt).getTime()) / (1000 * 60 * 60 * 24)
    );
    if (daysSinceCreated < 7) {
      return { type: 'new', label: 'New' };
    }
    return null;
  };

  const badge = getBadge();

  const getBadgeStyles = (type: ProductCardBadge['type']) => {
    switch (type) {
      case 'sale':
        return { backgroundColor: '#ef4444', color: '#fff' };
      case 'new':
        return { backgroundColor: '#10b981', color: '#fff' };
      case 'popular':
        return { backgroundColor: '#f59e0b', color: '#fff' };
      default:
        return {};
    }
  };

  const handleAddToCartClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onAddToCart) {
      onAddToCart(product.id);
    }
  };

  const handleClick = () => {
    if (onViewDetail) {
      onViewDetail(product.id);
    }
  };

  const renderStars = (rating: number) => {
    return Array.from({ length: 5 }, (_, i) => (
      <span
        key={i}
        className={`star ${i < Math.floor(rating) ? 'filled' : i < rating ? 'half' : ''}`}
      >
        ★
      </span>
    ));
  };

  return (
    <article className="product-card" onClick={handleClick}>
      <div className="product-image-container">
        <img
          src={product.imageUrl}
          alt={product.name}
          className="product-image"
          loading="lazy"
        />
        {badge && (
          <span
            className="product-badge"
            style={getBadgeStyles(badge.type)}
          >
            {badge.label}
          </span>
        )}
        <div className="product-actions-overlay">
          <button
            className="quick-view-btn"
            onClick={(e) => {
              e.stopPropagation();
              handleClick();
            }}
            aria-label="Quick view"
          >
            👁️
          </button>
        </div>
      </div>

      <div className="product-content">
        <div className="product-category">{product.category?.name || 'Uncategorized'}</div>

        <h3 className="product-name">{product.name}</h3>

        <div className="product-rating">
          <div className="stars">{renderStars(product.rating)}</div>
          <span className="rating-value">({product.rating.toFixed(1)})</span>
        </div>

        <div className="product-price">
          <span className="price-current">${product.price.toFixed(2)}</span>
          {product.price > 150 && (
            <span className="price-original">${(product.price * 1.2).toFixed(2)}</span>
          )}
        </div>

        <div className="product-footer">
          <div className="stock-status">
            {product.stock > 0 ? (
              <>
                <span className="stock-dot in-stock"></span>
                <span>In Stock</span>
              </>
            ) : (
              <>
                <span className="stock-dot out-of-stock"></span>
                <span>Out of Stock</span>
              </>
            )}
          </div>

          <Button
            variant="primary"
            size="sm"
            onClick={handleAddToCartClick}
            disabled={isAddingToCart || product.stock === 0}
            loading={isAddingToCart}
          >
            {isAddingToCart ? 'Adding...' : product.stock === 0 ? 'Unavailable' : 'Add to Cart'}
          </Button>
        </div>
      </div>
    </article>
  );
};

export default ProductCard;

import React, { useId } from 'react';
import type { InputProps } from '../types';

const Input: React.FC<InputProps> = ({
  label,
  name,
  type = 'text',
  placeholder,
  value,
  onChange,
  onBlur,
  error,
  disabled = false,
  required = false,
  fullWidth = false,
  className = '',
  autoComplete,
  maxLength,
  minLength,
}) => {
  const inputId = useId();
  const errorId = `${inputId}-error`;
  const hasError = Boolean(error);

  const containerStyles: React.CSSProperties = {
    display: 'flex',
    flexDirection: 'column',
    gap: '0.375rem',
    width: fullWidth ? '100%' : 'auto',
  };

  const labelStyles: React.CSSProperties = {
    fontSize: '0.875rem',
    fontWeight: '500',
    color: '#374151',
  };

  const inputStyles: React.CSSProperties = {
    padding: '0.625rem 0.875rem',
    fontSize: '1rem',
    fontFamily: 'inherit',
    borderRadius: '0.5rem',
    border: hasError ? '2px solid #ef4444' : '1px solid #d1d5db',
    outline: 'none',
    transition: 'border-color 0.2s, box-shadow 0.2s',
    width: '100%',
    backgroundColor: disabled ? '#f3f4f6' : '#ffffff',
    color: '#111827',
  };

  const inputFocusStyles: React.CSSProperties = {
    borderColor: hasError ? '#ef4444' : '#3b82f6',
    boxShadow: hasError
      ? '0 0 0 3px rgba(239, 68, 68, 0.1)'
      : '0 0 0 3px rgba(59, 130, 246, 0.1)',
  };

  const errorStyles: React.CSSProperties = {
    fontSize: '0.75rem',
    color: '#ef4444',
    marginTop: '0.25rem',
  };

  const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
    Object.assign(e.target.style, inputFocusStyles);
  };

  const handleBlur = (e: React.FocusEvent<HTMLInputElement>) => {
    Object.assign(e.target.style, {
      borderColor: hasError ? '#ef4444' : '#d1d5db',
      boxShadow: 'none',
    });
    if (onBlur) {
      onBlur(e);
    }
  };

  return (
    <div style={containerStyles} className={`input-group ${className}`}>
      {label && (
        <label htmlFor={inputId} style={labelStyles}>
          {label}
          {required && <span className="required-indicator"> *</span>}
        </label>
      )}
      <input
        id={inputId}
        name={name}
        type={type}
        placeholder={placeholder}
        value={value}
        onChange={onChange}
        onFocus={handleFocus}
        onBlur={handleBlur}
        disabled={disabled}
        required={required}
        autoComplete={autoComplete}
        maxLength={maxLength}
        minLength={minLength}
        aria-invalid={hasError}
        aria-describedby={hasError ? errorId : undefined}
        style={inputStyles}
        className="input-field"
      />
      {hasError && (
        <span id={errorId} style={errorStyles} className="input-error" role="alert">
          {error}
        </span>
      )}
    </div>
  );
};

export default Input;

import React from 'react';
import type { LoadingProps } from '../types';

const sizeConfig: Record<string, { spinner: number; fontSize: string }> = {
  sm: { spinner: 16, fontSize: '0.875rem' },
  md: { spinner: 24, fontSize: '1rem' },
  lg: { spinner: 40, fontSize: '1.25rem' },
};

const Loading: React.FC<LoadingProps> = ({
  size = 'md',
  text,
  fullPage = false,
  overlay = false,
  className = '',
}) => {
  const config = sizeConfig[size];

  const containerStyles: React.CSSProperties = fullPage
    ? {
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: overlay ? 'rgba(255, 255, 255, 0.9)' : 'transparent',
        zIndex: overlay ? 9999 : 'auto',
      }
    : {
        display: 'inline-flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '1rem',
      };

  const spinnerStyles: React.CSSProperties = {
    width: config.spinner,
    height: config.spinner,
    border: `3px solid #e5e7eb`,
    borderTopColor: '#3b82f6',
    borderRadius: '50%',
    animation: 'spin 0.8s linear infinite',
  };

  const textStyles: React.CSSProperties = {
    marginTop: '0.75rem',
    fontSize: config.fontSize,
    color: '#6b7280',
    fontWeight: '500',
  };

  const keyframes = `
    @keyframes spin {
      from {
        transform: rotate(0deg);
      }
      to {
        transform: rotate(360deg);
      }
    }
  `;

  return (
    <>
      <style>{keyframes}</style>
      <div
        style={containerStyles}
        className={`loading ${fullPage ? 'loading-fullpage' : ''} ${className}`}
        role="status"
        aria-live="polite"
      >
        <div style={spinnerStyles} className="loading-spinner">
          <span className="sr-only">Loading...</span>
        </div>
        {text && <p style={textStyles}>{text}</p>}
      </div>
    </>
  );
};

export default Loading;

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [react()],

  // Server configuration
  server: {
    port: 3000,
    open: true,
    proxy: {
      '/api': {
        target: 'http://localhost:5000',
        changeOrigin: true,
        secure: false,
      },
    },
    cors: true,
  },

  // Preview configuration
  preview: {
    port: 4173,
  },

  // Build configuration
  build: {
    outDir: 'dist',
    sourcemap: false,
    minify: 'terser',
    rollupOptions: {
      output: {
        manualChunks: {
          vendor: ['react', 'react-dom', 'react-router-dom'],
