/* ============================================
   CSS Variables / Design Tokens
   ============================================ */
:root {
  /* Primary Colors */
  --color-primary-50: #f0f9ff;
  --color-primary-100: #e0f2fe;
  --color-primary-200: #bae6fd;
  --color-primary-300: #7dd3fc;
  --color-primary-400: #38bdf8;
  --color-primary-500: #0ea5e9;
  --color-primary-600: #0284c7;
  --color-primary-700: #0369a1;
  --color-primary-800: #075985;
  --color-primary-900: #0c4a6e;

  /* Secondary Colors */
  --color-secondary-50: #faf5ff;
  --color-secondary-100: #f3e8ff;
  --color-secondary-200: #e9d5ff;
  --color-secondary-500: #a855f7;
  --color-secondary-600: #9333ea;

  /* Neutral Colors */
  --color-neutral-50: #fafafa;
  --color-neutral-100: #f5f5f5;
  --color-neutral-200: #e5e5e5;
  --color-neutral-300: #d4d4d4;
  --color-neutral-400: #a3a3a3;
  --color-neutral-500: #737373;
  --color-neutral-600: #525252;
  --color-neutral-700: #404040;
  --color-neutral-800: #262626;
  --color-neutral-900: #171717;

  /* Semantic Colors */
  --color-success: #22c55e;
  --color-warning: #f59e0b;
  --color-danger: #ef4444;
  --color-info: #3b82f6;

  /* Typography */
  --font-sans: 'Inter', ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  --font-mono: ui-monospace, SFMono-Regular, 'SF Mono', Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;
  --font-display: 'Playfair Display', Georgia, serif;

  /* Spacing */
  --spacing-unit: 0.25rem;

  /* Border Radius */
  --radius-sm: 0.25rem;
  --radius-md: 0.375rem;
  --radius-lg: 0.5rem;
  --radius-xl: 0.75rem;
  --radius-2xl: 1rem;
  --radius-full: 9999px;

  /* Shadows */
  --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
  --shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.1), 0 8px 10px -6px rgb(0 0 0 / 0.1);

  /* Transitions */
  --transition-fast: 150ms;
  --transition-base: 300ms;
  --transition-slow: 500ms;

  /* Z-Index Scale */
  --z-dropdown: 10;
  --z-sticky: 20;
  --z-fixed: 30;
  --z-modal-backdrop: 40;
  --z-modal: 50;
  --z-popover: 60;
  --z-tooltip: 70;
  --z-toast: 80;
}

/* ============================================
   Base / Reset Styles
   ============================================ */
@layer base {
  *,
  *::before,
  *::after {
    box-sizing: border-box;
  }

  html {
    @apply scroll-smooth;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
  }

  body {
    @apply bg-neutral-50 text-neutral-900 font-sans;
    @apply min-h-screen m-0 p-0;
    @apply leading-normal;
    @apply subpixel-antialiased;
  }

  /* Scrollbar Styling */
  ::-webkit-scrollbar {
    @apply w-2 h-2;
  }

  ::-webkit-scrollbar-track {
    @apply bg-neutral-100;
  }

  ::-webkit-scrollbar-thumb {
    @apply bg-neutral-300 rounded-full;
    @apply hover:bg-neutral-400;
  }

  ::-webkit-scrollbar-corner {
    @apply bg-neutral-100;
  }

  /* Selection */
  ::selection {
    @apply bg-primary-200 text-primary-900;
  }

  /* Focus Visible */
  :focus-visible {
    @apply outline-none ring-2 ring-primary-500 ring-offset-2;
    @apply ring-offset-neutral-50;
  }

  /* Headings */
  h1, h2, h3, h4, h5, h6 {
    @apply font-semibold text-neutral-900;
    @apply leading-tight tracking-tight;
  }

  h1 { @apply text-4xl md:text-5xl; }
  h2 { @apply text-3xl md:text-4xl; }
  h3 { @apply text-2xl md:text-3xl; }
  h4 { @apply text-xl md:text-2xl; }
  h5 { @apply text-lg md:text-xl; }
  h6 { @apply text-base md:text-lg; }

  /* Paragraph */
  p {
    @apply my-4 leading-relaxed;
  }

  /* Links */
  a {
    @apply text-primary-600 no-underline;
    @apply hover:text-primary-700 hover:underline;
    @apply transition-colors duration-200;
  }

  /* Images */
  img, picture, video, canvas, svg {
    @apply block max-w-full h-auto;
  }

  /* Form Elements */
  input, button, textarea, select {
    @apply font-sans text-inherit;
  }

  button {
    @apply cursor-pointer bg-transparent border-none p-0;
  }

  /* Lists */
  ul, ol {
    @apply list-none p-0 m-0;
  }

  /* Tables */
  table {
    @apply w-full border-collapse;
  }

  /* Horizontal Rule */
  hr {
    @apply border-0 border-t border-neutral-200 my-6;
  }

  /* Disabled State */
  :disabled {
    @apply cursor-not-allowed opacity-50;
  }
}

/* ============================================
   Component Styles
   ============================================ */
@layer components {
  /* Buttons */
  .btn {
    @apply inline-flex items-center justify-center;
    @apply px-4 py-2 rounded-lg font-medium;
    @apply transition-all duration-200;
    @apply focus:outline-none focus:ring-2 focus:ring-offset-2;
    @apply disabled:cursor-not-allowed disabled:opacity-50;
  }

  .btn-primary {
    @apply btn;
    @apply bg-primary-600 text-white;
    @apply hover:bg-primary-700;
    @apply focus:ring-primary-500;
  }

  .btn-secondary {
    @apply btn;
    @apply bg-neutral-200 text-neutral-900;
    @apply hover:bg-neutral-300;
    @apply focus:ring-neutral-400;
  }

  .btn-outline {
    @apply btn;
    @apply border-2 border-primary-600 text-primary-600 bg-transparent;
    @apply hover:bg-primary-50;
    @apply focus:ring-primary-500;
  }

  .btn-ghost {
    @apply btn;
    @apply bg-transparent text-neutral-700;
    @apply hover:bg-neutral-100;
    @apply focus:ring-neutral-400;
  }

  .btn-danger {
    @apply btn;
    @apply bg-danger-600 text-white;
    @apply hover:bg-danger-700;
    @apply focus:ring-danger-500;
  }

  .btn-success {
    @apply btn;
    @apply bg-success-600 text-white;
    @apply hover:bg-success-700;
    @apply focus:ring-success-500;
  }

  .btn-sm {
    @apply px-3 py-1.5 text-sm;
  }

  .btn-lg {
    @apply px-6 py-3 text-lg;
  }

  .btn-icon {
    @apply p-2 rounded-full;
  }

  /* Input Fields */
  .input {
    @apply w-full px-4 py-2;
    @apply bg-white text-neutral-900;
    @apply border border-neutral-300 rounded-lg;
    @apply transition-all duration-200;
    @apply placeholder:text-neutral-400;
    @apply focus:border-primary-500 focus:ring-2 focus:ring-primary-500/20;
    @apply disabled:bg-neutral-100 disabled:cursor-not-allowed;
  }

  .input-error {
    @apply border-danger-500;
    @apply focus:border-danger-500 focus:ring-danger-500/20;
  }

  .input-success {
    @apply border-success-500;
    @apply focus:border-success-500 focus:ring-success-500/20;
  }

  /* Cards */
  .card {
    @apply bg-white rounded-xl shadow-card;
    @apply transition-shadow duration-300;
  }

  .card-hover {
    @apply card;
    @apply hover:shadow-card-hover;
  }

  .card-bordered {
    @apply bg-white rounded-xl border border-neutral-200;
  }

  /* Badges */
  .badge {
    @apply inline-flex items-center px-2.5 py-0.5;
    @apply text-xs font-medium rounded-full;
  }

  .badge-primary {
    @apply badge bg-primary-100 text-primary-800;
  }

  .badge-success {
    @apply badge bg-success-100 text-success-800;
  }

  .badge-warning {
    @apply badge bg-warning-100 text-warning-800;
  }

  .badge-danger {
    @apply badge bg-danger-100 text-danger-800;
  }

  .badge-neutral {
    @apply badge bg-neutral-100 text-neutral-800;
  }

  /* Container */
  .container-app {
    @apply container mx-auto px-4 sm:px-6 lg:px-8;
  }

  /* Navigation */
  .nav-link {
    @apply px-3 py-2 rounded-lg text-sm font-medium;
    @apply text-neutral-600;
    @apply transition-colors duration-200;
    @apply hover:bg-neutral-100 hover:text-neutral-900;
  }

  .nav-link-active {
    @apply bg-primary-50 text-primary-700;
    @apply hover:bg-primary-100 hover:text-primary-800;
  }

  /* Divider */
  .divider {
    @apply border-t border-neutral-200;
  }

  /* Skeleton Loader */
  .skeleton {
    @apply animate-pulse bg-neutral-200 rounded;
  }

  .skeleton-text {
    @apply skeleton h-4 w-full;
  }

  .skeleton-avatar {
    @apply skeleton w-10 h-10 rounded-full;
  }

  .skeleton-image {
    @apply skeleton w-full aspect-square;
  }

  /* Toast / Alert */
  .alert {
    @apply relative px-4 py-3 rounded-lg;
    @apply text-sm font-medium;
  }

  .alert-info {
    @apply alert bg-info-50 text-info-800 border border-info-200;
  }

  .alert-success {
    @apply alert bg-success-50 text-success-800 border border-success-200;
  }

  .alert-warning {
    @apply alert bg-warning-50 text-warning-800 border border-warning-200;
  }

  .alert-danger {
    @apply alert bg-danger-50 text-danger-800 border border-danger-200;
  }

  /* Modal Backdrop */
  .modal-backdrop {
    @apply fixed inset-0 z-40;
    @apply bg-neutral-900/50 backdrop-blur-sm;
    @apply transition-opacity duration-300;
  }

  /* Modal */
  .modal {
    @apply fixed z-50 top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2;
    @apply w-full max-w-lg max-h-[90vh] overflow-auto;
    @apply bg-white rounded-2xl shadow-xl;
    @apply animate-scale-in;
  }

  /* Tooltip */
  .tooltip {
    @apply absolute z-50 px-2 py-1 text-xs font-medium;
    @apply bg-neutral-900 text-white rounded;
    @apply pointer-events-none opacity-0;
    @apply transition-opacity duration-200;
  }

  /* Dropdown Menu */
  .dropdown-menu {
    @apply absolute z-50 mt-2 w-56;
    @apply bg-white rounded-xl shadow-lg ring-1 ring-neutral-200;
    @apply py-1;
    @apply animate-fade-in;
  }

  .dropdown-item {
    @apply block w-full px-4 py-2 text-left text-sm;
    @apply text-neutral-700;
    @apply transition-colors duration-150;
    @apply hover:bg-neutral-100 hover:text-neutral-900;
    @apply focus:outline-none focus:bg-neutral-100 focus:text-neutral-900;
  }

  /* Spinner */
  .spinner {
    @apply animate-spin rounded-full border-2 border-current border-t-transparent;
  }

  .spinner-sm {
    @apply spinner w-4 h-4;
  }

  .spinner-md {
    @apply spinner w-6 h-6;
  }

  .spinner-lg {
    @apply spinner w-8 h-8;
  }

  /* Avatar */
  .avatar {
    @apply relative inline-flex items-center justify-center;
    @apply w-10 h-10 rounded-full overflow-hidden;
    @apply bg-neutral-200 text-neutral-600 font-medium;
  }

  .avatar-sm {
    @apply w-8 h-8 text-xs;
  }

  .avatar-lg {
    @apply w-12 h-12 text-base;
  }

  .avatar-xl {
    @apply w-16 h-16 text-lg;
  }

  /* Progress Bar */
  .progress {
    @apply w-full h-2 bg-neutral-200 rounded-full overflow-hidden;
  }

  .progress-bar {
    @apply h-full bg-primary-600 rounded-full;
    @apply transition-all duration-500 ease-out;
  }

  /* Checkbox */
  .checkbox {
    @apply w-5 h-5 rounded border-2 border-neutral-300;
    @apply checked:bg-primary-600 checked:border-primary-600;
    @apply transition-colors duration-200;
    @apply cursor-pointer;
    @apply focus:ring-2 focus:ring-primary-500 focus:ring-offset-2;
  }

  /* Radio */
  .radio {
    @apply w-5 h-5 rounded-full border-2 border-neutral-300;
    @apply checked:border-primary-600 checked:bg-primary-600;
    @apply checked:bg-primary-600/20;
    @apply transition-colors duration-200;
    @apply cursor-pointer;
    @apply focus:ring-2 focus:ring-primary-500 focus:ring-offset-2;
  }

  /* Toggle / Switch */
  .toggle {
    @apply relative inline-flex h-6 w-11 items-center rounded-full;
    @apply transition-colors duration-200 ease-in-out;
    @apply cursor-pointer;
    @apply focus:outline-none focus:ring-2 focus:ring-primary-500 focus:ring-offset-2;
  }

  .toggle-enabled {
    @apply bg-primary-600;
  }

  .toggle-disabled {
    @apply bg-neutral-300;
  }

  .toggle-handle {
    @apply inline-block h-4 w-4 transform rounded-full bg-white shadow;
    @apply transition-transform duration-200 ease-in-out;
  }

  .toggle-enabled .toggle-handle {
    @apply translate-x-6;
  }

  .toggle-disabled .toggle-handle {
    @apply translate-x-1;
  }
}

/* ============================================
   Utility Classes
   ============================================ */
@layer utilities {
  /* Text Utilities */
  .text-balance {
    text-wrap: balance;
  }

  .text-pretty {
    text-wrap: pretty;
  }

  /* Gradient Text */
  .gradient-text {
    @apply bg-clip-text text-transparent;
    @apply bg-gradient-to-r from-primary-600 to-secondary-600;
  }

  /* Glass Effect */
  .glass {
    @apply bg-white/70 backdrop-blur-md;
    @apply border border-white/20;
  }

  /* Truncate Multi-line */
  .line-clamp-1 {
    display: -webkit-box;
    -webkit-line-clamp: 1;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .line-clamp-2 {
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .line-clamp-3 {
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  /* Hide Scrollbar */
  .hide-scrollbar {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .hide-scrollbar::-webkit-scrollbar {
    display: none;
  }

  /* Center Content */
  .center-content {
    @apply flex items-center justify-center;
  }

  /* Aspect Square */
  .aspect-square {
    aspect-ratio: 1 / 1;
  }

  /* Animation Pause */
  .animation-pause {
    animation-play-state: paused;
  }

  /* Ring Utilities */
  .ring-inset {
    --tw-ring-inset: inset;
  }

  /* Safe Area Insets */
  .safe-top {
    padding-top: env(safe-area-inset-top);
  }

  .safe-bottom {
    padding-bottom: env(safe-area-inset-bottom);
  }

  .safe-left {
    padding-left: env(safe-area-inset-left);
  }

  .safe-right {
    padding-right: env(safe-area-inset-right);
  }

  /* Custom Scrollbar for Webkit */
  .scrollbar-thin {
    scrollbar-width: thin;
  }

  .scrollbar-none {
    scrollbar-width: none;
  }

  .scrollbar-none::-webkit-scrollbar {
    display: none;
  }

  /* Hover Scale */
  .hover-scale {
    @apply transition-transform duration-200;
    @apply hover:scale-105;
  }

  /* Stagger Animation Delays */
  .delay-100 { animation-delay: 100ms; }
  .delay-200 { animation-delay: 200ms; }
  .delay-300 { animation-delay: 300ms; }
  .delay-400 { animation-delay: 400ms; }
  .delay-500 { animation-delay: 500ms; }
}

/* ============================================
   Custom Animations
   ============================================ */
@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

.shimmer {
  background: linear-gradient(
    90deg,
    transparent 0%,
    rgba(255, 255, 255, 0.4) 50%,
    transparent 100%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
}

/* ============================================
   Media Print Styles
   ============================================ */
@media print {
  body {
    @apply bg-white text-black;
  }

  .no-print {
    display: none !important;
  }

  a {
    @apply text-black no-underline;
  }

  a[href]::after {
    content: ' (' attr(href) ')';
  }
}

/* ============================================
   Dark Mode Support (if needed)
   ============================================ */
@media (prefers-color-scheme: dark) {
  /* Auto dark mode based on system preference */
  :root.auto-dark {
    --color-primary-50: #0c4a6e;
    --color-primary-100: #075985;
    --color-primary-200: #0284c7;
    --color-neutral-50: #0a0a0a;
    --color-neutral-100: #171717;
    --color-neutral-200: #262626;
    --color-neutral-900: #fafafa;
  }
}

